INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 1, 62, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, 1, "2025/01/31 12:00:00", 1000001, 3.414, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 2, 62, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 1, 1, "2025/01/31 12:00:00", 1000002, 3.099, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 3, 63, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 1, 1, "2025/01/31 12:00:00", 1000003, 2.801, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 4, 63, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 2, 1, "2025/01/31 12:00:00", 1000004, 0.0, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 5, 64, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2, 1, "2025/01/31 12:00:00", 1000005, 2.12, 190801, 0.0, "カリン", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 6, 64, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1, 1, "2025/01/31 12:00:00", 1000006, 1.68, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 7, 64, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2, 1, "2025/01/31 12:00:00", 1000007, 2.33, 190801, 0.0, "カリン", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 3, 10201, "2025/01/31 12:00:00", 1020101, 5.18, 133701, -6.0, "ラビリスタ", 7);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1, 10201, "2025/01/31 12:00:00", 1020102, 8.77, 133901, -2.0, "クリスティーナ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 6, 10201, "2025/01/31 12:00:00", 1020103, 15.5, 133801, 0.0, "ネネカ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 2, 10202, "2025/02/28 12:00:00", 1020201, 9.061, 134301, 0.0, "ランファ", 5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1, 10202, "2025/02/28 12:00:00", 1020202, 7.699, 134401, 0.0, "チカ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1, 10203, "2025/03/31 12:00:00", 1020301, 8.595, 134601, 0.0, "アオイ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1, 10203, "2025/03/31 12:00:00", 1020302, 7.758, 134501, 0.0, "クローチェ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 2, 10204, "2025/04/30 12:00:00", 1020401, 7.0, 132302, 0.0, "ルイズマリー", 6);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1, 10204, "2025/04/30 12:00:00", 1020402, 7.904, 132402, 0.0, "イロハ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 4, 10204, "2025/04/30 12:00:00", 1020403, 8.487, 132502, 0.0, "ソノ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1, 10205, "2025/05/31 12:00:00", 1020502, 8.763, 134901, 0.0, "カノン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1, 10205, "2025/05/31 12:00:00", 1020503, 6.417, 134801, 0.0, "ツムギ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 3, 10206, "2025/06/30 12:00:00", 1020601, 10.335, 135001, 0.0, "エリス", 7);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 2, 10206, "2025/06/30 12:00:00", 1020602, 6.281, 135101, 0.0, "シェフィ", 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1, 10206, "2025/06/30 12:00:00", 1020603, 12.244, 135201, 0.0, "プレシア", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 2, 10207, "2025/07/31 12:00:00", 1020701, 6.339, 135301, 0.0, "クリア", 8);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 7, 10207, "2025/07/31 12:00:00", 1020702, 8.184, 135401, 0.0, "アネモネ", 9);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 9, 10208, "2025/08/31 12:00:00", 1020801, 3.906, 129101, 0.0, "アイラ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1, 10208, "2025/08/31 12:00:00", 1020802, 14.465, 129201, 0.0, "シナツ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 4, 10208, "2025/08/31 12:00:00", 1020803, 8.662, 100101, 0.0, "ヒヨリ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 401, 61, "2030/01/01 14:59:59", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1, 10208, "2025/08/31 12:00:00", 1020804, 10.915, 100301, 0.0, "レイ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1, 10209, "2025/09/30 12:00:00", 1020901, 6.042, 135802, 0.0, "ユキノ", 7);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 4, 10209, "2025/09/30 12:00:00", 1020902, 9.402, 135903, 0.0, "サツキ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8, 10209, "2025/09/30 12:00:00", 1020903, 8.16, 136902, 0.0, "ルルィ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 3, 10210, "2025/10/31 12:00:00", 1021001, 5.0, 137401, 0.0, "カスミ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 4, 10210, "2025/10/31 12:00:00", 1021002, 8.12, 136001, 0.0, "アラクネ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 4, 10210, "2025/10/31 12:00:00", 1021003, 6.386, 136202, 0.0, "ナーナ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 3, 10211, "2025/11/30 12:00:00", 1021101, 7.438, 136402, 0.0, "ユイ", 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1, 10211, "2025/11/30 12:00:00", 1021102, 8.35, 136302, 0.0, "ミソラ", 5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1, 10212, "2025/12/31 12:00:00", 1021201, 5.0, 136501, 0.0, "シズル", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1, 10212, "2025/12/31 12:00:00", 1021202, 5.25, 137902, 0.0, "リノ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1, 10212, "2025/12/31 12:00:00", 1021203, 7.5, 106801, 0.0, "ラビリスタ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1, 10213, "2026/01/31 12:00:00", 1021301, 8.204, 126501, 0.0, "ライラエル", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1, 10213, "2026/01/31 12:00:00", 1021302, 7.176, 129701, 0.0, "ネフィ＝ネラ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1, 10213, "2026/01/31 12:00:00", 1021303, 8.602, 133101, 0.0, "ヴァイオレット", 5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 102, 61, "2030/01/01 14:59:59", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1, 10213, "2026/02/06 12:00:00", 1021304, 10.14, 138101, 0.0, "ライラエル", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 202, 61, "2030/01/01 14:59:59", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1, 10213, "2026/02/06 12:00:00", 1021305, 10.152, 138201, 0.0, "ネフィ＝ネラ", 7);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 302, 61, "2030/01/01 14:59:59", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 4, 10213, "2026/02/06 12:00:00", 1021306, 9.688, 138001, 0.0, "ヴァイオレット", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 401, 61, "2030/01/01 14:59:59", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 2, 10213, "2026/02/12 12:00:00", 1021307, 5.928, 138301, 0.0, "ペコリーヌ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 4, 10214, "2026/02/28 12:00:00", 1021401, 9.19, 138702, 0.0, "ワカナ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1, 10214, "2026/02/28 12:00:00", 1021402, 8.724, 138802, 0.0, "シオリ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 4, 10215, "2026/03/31 12:00:00", 1021501, 7.758, 138902, 0.0, "グレイス", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 6, 10215, "2026/03/31 12:00:00", 1021502, 6.375, 139002, 0.0, "キョウカ", 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 6, 10215, "2026/03/31 12:00:00", 1021503, 6.173, 136902, 0.0, "ルルィ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 6, 10216, "2026/04/30 12:00:00", 1021601, 4.202, 139202, 0.0, "ミホ", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 6, 10216, "2026/04/30 12:00:00", 1021602, 2.842, 139302, 0.0, "マホ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 4, 10216, "2026/04/30 12:00:00", 1021603, 4.598, 139402, 0.0, "エリカ", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 101, 61, "2030/01/01 14:59:59", "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 4, 10217, "2026/05/31 12:00:00", 1021701, 6.533, 125802, 0.0, "リリ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 301, 61, "2030/01/01 14:59:59", "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 3, 10217, "2026/05/31 12:00:00", 1021702, 5.0, 126102, 0.0, "プレシア", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 201, 61, "2030/01/01 14:59:59", "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 3, 10217, "2026/05/31 12:00:00", 1021703, 5.214, 126002, 0.0, "クリア", 4);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 102, 61, "2030/01/01 14:59:59", "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 1, 10217, "2026/05/31 12:00:00", 1021704, 8.781, 139501, 0.0, "リリ", 3);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 202, 61, "2030/01/01 14:59:59", "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 2, 10217, "2026/05/31 12:00:00", 1021705, 6.529, 139601, 0.0, "クリア", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-285.0, 302, 61, "2030/01/01 14:59:59", "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 3, 10217, "2026/05/31 12:00:00", 1021706, 3.195, 139701, 0.0, "プレシア", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 1, 62, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, 2, "2026/04/10 12:00:00", 2000001, 3.414, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 2, 62, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 1, 2, "2026/04/10 12:00:00", 2000002, 3.099, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 3, 63, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 1, 2, "2026/04/10 12:00:00", 2000003, 2.801, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-416.5, 4, 63, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 2, 2, "2026/04/10 12:00:00", 2000004, 0.0, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 5, 64, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2, 2, "2026/04/10 12:00:00", 2000005, 2.12, 190801, 0.0, "カリン", 1);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 6, 64, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1, 2, "2026/04/10 12:00:00", 2000006, 1.68, 190801, 0.0, "カリン", 2);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (-363.0, 7, 64, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2, 2, "2026/04/10 12:00:00", 2000007, 2.33, 190801, 0.0, "カリン", 1);
